import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

/**
 * Tests for extension properties with custom getters that have annotations or modifiers.
 * See https://github.com/pinterest/ktlint/issues/2040
 */
class PropertyNamingRuleExtensionPropertyTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an extension property with getter that has annotation then do not emit`() {
        val code =
            """
            val Context.adsDelegateFactory @SuppressLint("WrongConstant") get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with private getter then do not emit`() {
        val code =
            """
            val Context.adsDelegateFactory private get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with annotated private getter then do not emit`() {
        val code =
            """
            val Context.adsDelegateFactory @SuppressLint("WrongConstant") private get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with simple getter then do not emit`() {
        val code =
            """
            val Context.adsDelegateFactory get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level val property with annotated getter then do not emit`() {
        val code =
            """
            val foo @SuppressWarnings("unused") get() = "foo"
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an object val property with private getter then do not emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val foo
                        private get() = foobar()
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

